15	export type MailDeliveryResult =
16	  | { delivered: true; provider: "resend" | "smtp"; id?: string }
17	  | { delivered: false; reason: string; provider?: "console" };
18	
19	type ResendSender = (
20	  apiKey: string,
21	  message: SendMailInput,
22	) => Promise<MailDeliveryResult>;
23	
24	type SmtpSender = (message: SendMailInput) => Promise<MailDeliveryResult>;
25	
26	let resendSender: ResendSender = sendViaResend;
27	let smtpSender: SmtpSender = sendViaSmtp;
28	
29	export function __setMailSendersForTesting(senders: {
30	  resend?: ResendSender;
31	  smtp?: SmtpSender;
32	}) {
33	  if (senders.resend) resendSender = senders.resend;
34	  if (senders.smtp) smtpSender = senders.smtp;
35	}
36	
37	export function __resetMailSendersForTesting() {
38	  resendSender = sendViaResend;
39	  smtpSender = sendViaSmtp;
40	}
41	
42	export async function sendMail(
43	  message: SendMailInput,
44	): Promise<MailDeliveryResult> {
45	  if (isPlaceholderRecipient(message.to)) {
46	    console.warn("[mail] skipped placeholder recipient", {
47	      to: message.to,
48	      subject: message.subject,
49	    });
50	    return { delivered: false, reason: "placeholder recipient" };
51	  }
52	
53	  const resendKey = process.env.RESEND_API_KEY?.trim();
54	  if (resendKey) {
55	    return resendSender(resendKey, message);
56	  }
57	
58	  if (smtpConfigured()) {
59	    return smtpSender(message);
60	  }
61	
62	  console.info("[mail] no provider configured", {
63	    to: message.to,
64	    subject: message.subject,
65	  });
66	  return {
67	    delivered: false,
68	    reason: "no provider configured",
69	    provider: "console",
70	  };
71	}
72	
73	function smtpConfigured(): boolean {
74	  return Boolean(
75	    process.env.SMTP_HOST?.trim() &&
76	      process.env.SMTP_PORT?.trim() &&
77	      process.env.SMTP_USER?.trim() &&
78	      process.env.SMTP_PASS?.trim(),
79	  );
80	}
81	
82	function isPlaceholderRecipient(value: string): boolean {
83	  const address = extractAddress(value).toLowerCase();
84	  return (
85	    address === "founder-alpha@example.invalid" ||
86	    address.endsWith(".invalid") ||
87	    address.endsWith("@example.invalid")
88	  );
89	}
90	
91	async function sendViaResend(
92	  apiKey: string,
93	  message: SendMailInput,
94	): Promise<MailDeliveryResult> {
95	  const res = await fetch("https://api.resend.com/emails", {
96	    method: "POST",
97	    headers: {
98	      Authorization: `Bearer ${apiKey}`,
99	      "Content-Type": "application/json",
100	    },
101	    body: JSON.stringify({
102	      from: message.from,
103	      to: [message.to],
104	      subject: cleanHeader(message.subject),
105	      html: message.html,
106	      text: message.text,
107	      headers: message.headers,
108	    }),
109	  });
110	
111	  const payload = (await res.json().catch(() => ({}))) as { id?: string; message?: string };
112	  if (!res.ok) {
113	    throw new Error(
114	      `Resend send failed (${res.status}): ${payload.message || res.statusText}`,
115	    );
116	  }
117	  return { delivered: true, provider: "resend", id: payload.id };
118	}
119	
120	async function sendViaSmtp(message: SendMailInput): Promise<MailDeliveryResult> {
121	  const nodemailer = await loadOptionalNodemailer();
122	  if (nodemailer) {
123	    return sendViaNodemailer(nodemailer, message);
124	  }
125	  return sendViaSmtpSocket(message);
126	}
127	
128	async function sendViaNodemailer(
129	  nodemailer: { createTransport: (options: unknown) => { sendMail: (message: unknown) => Promise<{ messageId?: string }> } },
130	  message: SendMailInput,
131	): Promise<MailDeliveryResult> {
132	  const host = requiredEnv("SMTP_HOST");
133	  const port = Number.parseInt(requiredEnv("SMTP_PORT"), 10);
134	  const secure = port === 465 || envFlag("SMTP_SECURE");
135	  const starttls =
136	    !secure &&
137	    !["0", "false", "no"].includes(
138	      (process.env.SMTP_STARTTLS || "true").trim().toLowerCase(),
139	    );
140	  const transport = nodemailer.createTransport({
141	    host,
142	    port,
143	    secure,
144	    requireTLS: starttls,
145	    auth: {
146	      user: requiredEnv("SMTP_USER"),
147	      pass: requiredEnv("SMTP_PASS"),
148	    },
149	  });
150	  const result = await transport.sendMail({
151	    to: message.to,
152	    from: message.from,
153	    subject: cleanHeader(message.subject),
154	    html: message.html,
155	    text: message.text,
156	    headers: message.headers,
157	  });
158	  return { delivered: true, provider: "smtp", id: result.messageId };
159	}
160	
161	async function loadOptionalNodemailer(): Promise<{
162	  createTransport: (options: unknown) => { sendMail: (message: unknown) => Promise<{ messageId?: string }> };
163	} | null> {
164	  try {
165	    const load = new Function("specifier", "return import(specifier)") as (
166	      specifier: string,
167	    ) => Promise<{ default?: unknown; createTransport?: unknown }>;
168	    const mod = await load("nodemailer");
169	    const candidate = (mod.default || mod) as {
170	      createTransport?: unknown;
171	    };
172	    return typeof candidate.createTransport === "function"
173	      ? (candidate as {
174	          createTransport: (options: unknown) => {
175	            sendMail: (message: unknown) => Promise<{ messageId?: string }>;
176	          };
177	        })
178	      : null;
179	  } catch {
180	    return null;
181	  }
182	}
183	
184	async function sendViaSmtpSocket(message: SendMailInput): Promise<MailDeliveryResult> {
185	  const host = requiredEnv("SMTP_HOST");
186	  const port = Number.parseInt(requiredEnv("SMTP_PORT"), 10);
187	  const user = requiredEnv("SMTP_USER");
188	  const pass = requiredEnv("SMTP_PASS");
189	  if (!Number.isFinite(port) || port <= 0) {
190	    throw new Error("SMTP_PORT must be a positive integer");
191	  }
192	
193	  const secure = port === 465 || envFlag("SMTP_SECURE");
194	  const starttls =
195	    !secure &&
196	    !["0", "false", "no"].includes(
197	      (process.env.SMTP_STARTTLS || "true").trim().toLowerCase(),
198	    );
199	
200	  let socket: net.Socket | tls.TLSSocket = secure
201	    ? tls.connect({ host, port, servername: host, timeout: 20_000 })
202	    : net.connect({ host, port, timeout: 20_000 });
203	
204	  let smtp = new SmtpConnection(socket);
205	  await smtp.expect(220);
206	  await smtp.command(`EHLO ${smtpDomain()}`, 250);
207	
208	  if (starttls) {
209	    await smtp.command("STARTTLS", 220);
210	    socket = tls.connect({ socket, servername: host });
211	    smtp = new SmtpConnection(socket);
212	    await smtp.command(`EHLO ${smtpDomain()}`, 250);
213	  }
214	
215	  await smtp.command("AUTH LOGIN", 334);
216	  await smtp.command(Buffer.from(user).toString("base64"), 334);
217	  await smtp.command(Buffer.from(pass).toString("base64"), 235);
218	  await smtp.command(`MAIL FROM:<${extractAddress(message.from)}>`, 250);
219	  await smtp.command(`RCPT TO:<${extractAddress(message.to)}>`, [250, 251]);
220	  await smtp.command("DATA", 354);
221	  await smtp.data(renderSmtpMessage(message));
222	  await smtp.command("QUIT", [221, 250]).catch(() => undefined);
223	
224	  return { delivered: true, provider: "smtp" };
225	}
