227	class SmtpConnection {
228	  private buffer = "";
229	  private waiters: Array<(line: string) => void> = [];
230	
231	  constructor(private socket: net.Socket | tls.TLSSocket) {
232	    socket.setEncoding("utf8");
233	    socket.on("data", (chunk) => this.onData(String(chunk)));
234	    socket.on("error", (error) => {
235	      while (this.waiters.length) {
236	        this.waiters.shift()?.(`599 ${error.message}`);
237	      }
238	    });
239	  }
240	
241	  async command(command: string, expected: number | number[]): Promise<string> {
242	    this.socket.write(`${command}\r\n`);
243	    return this.expect(expected);
244	  }
245	
246	  async data(message: string): Promise<string> {
247	    this.socket.write(`${dotStuff(message)}\r\n.\r\n`);
248	    return this.expect(250);
249	  }
250	
